// An item that represents transactions on an escalation interface

class esc_seq_item extends alert_esc_seq_item;
  // An agent acting as an escalation receiver should generate an integrity error if this is true.
  rand bit        m_standalone_int_err;

  // Generated by esc_monitor: this item shows the current stage of the escelation handshake
  esc_handshake_e m_esc_handshake_sta;

  // The number of cycles that esc_p stayed high
  int unsigned    m_sig_cycle_cnt;

  `uvm_object_utils_begin(esc_seq_item)
    `uvm_field_int (m_standalone_int_err, UVM_DEFAULT)
    `uvm_field_enum(esc_handshake_e, m_esc_handshake_sta,   UVM_DEFAULT)
    `uvm_field_int (m_sig_cycle_cnt, UVM_DEFAULT)
  `uvm_object_utils_end

  extern function new (string name = "");
endclass : esc_seq_item

function esc_seq_item::new (string name = "");
  super.new(name);
endfunction
